
"use client"

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { useUser, useFirestore, useCollection, useMemoFirebase, useAuth } from '@/firebase';
import { collection, query, orderBy, limit } from 'firebase/firestore';
import { signOut } from 'firebase/auth';
import { 
  ArrowLeft, 
  Award, 
  Activity, 
  LayoutDashboard, 
  PieChart, 
  History, 
  User, 
  LogOut, 
  Crown,
  Zap,
  CheckCircle2,
  AlertTriangle
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';
import { cn } from '@/lib/utils';
import { SignalCard } from '@/components/SignalCard';
import { WhatsAppButton } from '@/components/WhatsAppButton';

export default function ManualAnalysisPage() {
  const router = useRouter();
  const auth = useAuth();
  const db = useFirestore();
  const { user, isUserLoading } = useUser();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    if (!isUserLoading && !user) {
      router.push('/login');
    }
  }, [user, isUserLoading, router]);

  const manualSignalsQuery = useMemoFirebase(() => {
    if (!db || !user) return null;
    return query(collection(db, 'manualSignals'), orderBy('createdAt', 'desc'), limit(15));
  }, [db, user]);

  const { data: signals, isLoading } = useCollection(manualSignalsQuery);

  const handleLogout = async () => {
    await signOut(auth);
    router.replace('/login');
  };

  if (!mounted || isUserLoading || !user) return (
    <div className="min-h-screen bg-background flex items-center justify-center">
      <Activity className="h-8 w-8 text-primary animate-spin" />
    </div>
  );

  return (
    <div className="min-h-screen bg-background text-foreground flex overflow-x-hidden">
      {/* Sidebar */}
      <aside className="w-64 border-r border-border bg-card/40 backdrop-blur-xl hidden lg:flex flex-col sticky top-0 h-screen">
        <div className="p-6">
          <div className="flex items-center gap-2 text-lg font-black tracking-tighter">
            <Award className="h-6 w-6 text-amber-500" />
            DEEBDATA <span className="text-amber-500">PRO</span>
          </div>
        </div>
        <nav className="flex-1 px-4 space-y-1">
          <NavItem href="/dashboard" icon={<LayoutDashboard className="h-4 w-4" />} label="AI Terminal" />
          <NavItem href="/manual-analysis" icon={<Award className="h-4 w-4" />} label="Hassan's Analysis" active />
          <NavItem href="/analysis" icon={<PieChart className="h-4 w-4" />} label="Technical Hub" />
          <NavItem href="/history" icon={<History className="h-4 w-4" />} label="Execution Log" />
          <NavItem href="/profile" icon={<User className="h-4 w-4" />} label="Identity" />
        </nav>
        <div className="p-4">
          <Button variant="ghost" className="w-full justify-start gap-3 text-muted-foreground hover:text-destructive h-10" onClick={handleLogout}>
            <LogOut className="h-4 w-4" /> Log Out
          </Button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col relative overflow-y-auto custom-scrollbar">
        <header className="h-16 border-b border-border flex items-center justify-between px-8 bg-card/40 backdrop-blur-md sticky top-0 z-40">
          <div className="flex items-center gap-4">
            <h1 className="text-xl font-black uppercase tracking-tighter flex items-center gap-2">
              <Award className="h-5 w-5 text-amber-500" /> Hassan Deeb Professional Insights
            </h1>
          </div>
          <div className="flex items-center gap-2">
             <div className="h-2 w-2 rounded-full bg-success animate-pulse" />
             <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Expert Link Active</span>
          </div>
        </header>

        <div className="p-8 space-y-8 container max-w-6xl mx-auto">
          <div className="bg-amber-500/10 border border-amber-500/20 rounded-3xl p-8 flex flex-col md:flex-row items-center gap-8 glassmorphism">
             <div className="h-24 w-24 rounded-3xl bg-black border border-amber-500/30 flex items-center justify-center">
                <Crown className="h-12 w-12 text-amber-500" />
             </div>
             <div className="space-y-2 text-center md:text-left flex-1">
                <h2 className="text-3xl font-black uppercase tracking-tighter">Master Analysis Hub</h2>
                <p className="text-muted-foreground text-sm font-medium leading-relaxed">
                  هذه الصفحة تحتوي حصرياً على توصيات وتحليلات الخبير <span className="text-amber-500 font-black">حسن ديب</span>. 
                  لا يتم استخدام الذكاء الاصطناعي هنا، كل صفقة هي نتاج خبرة مؤسساتية يدوية.
                </p>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {isLoading ? (
              <div className="col-span-full py-20 flex flex-col items-center justify-center">
                <Activity className="h-10 w-10 text-amber-500 animate-spin mb-4" />
                <p className="text-xs font-black uppercase tracking-widest text-muted-foreground">Fetching Hassan's Strategy...</p>
              </div>
            ) : signals?.length === 0 ? (
              <div className="col-span-full py-32 text-center border border-dashed border-border rounded-[3rem]">
                <Zap className="h-16 w-16 text-muted-foreground/20 mx-auto mb-6" />
                <p className="text-lg font-black uppercase text-muted-foreground">Hassan is currently analyzing the charts...</p>
                <p className="text-xs text-muted-foreground/50 uppercase mt-2">New institutional setups arriving soon.</p>
              </div>
            ) : (
              signals?.map((sig) => (
                <SignalCard 
                  key={sig.id}
                  symbol={sig.asset}
                  type={sig.asset.includes('/') ? 'Forex' : 'Crypto'}
                  signal={sig}
                  isLocked={false}
                />
              ))
            )}
          </div>
          
          <div className="p-6 rounded-3xl bg-primary/5 border border-primary/10 flex items-start gap-4">
             <AlertTriangle className="h-5 w-5 text-primary shrink-0 mt-1" />
             <p className="text-xs text-muted-foreground leading-relaxed">
               تذكر دائماً أن التداول ينطوي على مخاطر عالية. التحليلات اليدوية المقدمة من حسن ديب تعتمد على رؤية فنية مؤسساتية، ولكن يرجى دائماً الالتزام بإدارة رأس المال.
             </p>
          </div>
        </div>
      </main>
      <WhatsAppButton />
    </div>
  );
}

const NavItem = ({ href, icon, label, active }: { href: string, icon: React.ReactNode, label: string, active?: boolean }) => (
  <Link 
    href={href} 
    className={cn(
      "flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300",
      active ? 'bg-amber-500 text-black font-bold shadow-lg shadow-amber-500/20' : 'text-muted-foreground hover:bg-foreground/5 hover:text-foreground'
    )}
  >
    {icon} <span className="text-sm font-black uppercase tracking-widest">{label}</span>
  </Link>
);
